// NewGetIssuesForEpicMCPTool creates the MCP Tool instance for GetIssuesForEpic
func NewGetIssuesForEpicMCPTool() mcp.Tool {
	return mcp.NewToolWithRawSchema(
		"GetIssuesForEpic",
		"Get all issues for a specific epic - Returns all issues that belong to an epic on the board, for the given epic Id and the board Id.",
		[]byte(GetIssuesForEpicInputSchema),
	)
}

// GetIssuesForEpicHandler is the handler function for the GetIssuesForEpic tool.
// It reads tool arguments, forwards the request to the upstream service, and returns the response.
func GetIssuesForEpicHandler(ctx context.Context, request mcp.CallToolRequest) (*mcp.CallToolResult, error) {
	upstream := mcputils.GetUpstreamEndpoint()

	args := request.GetArguments()
	if args == nil {
		args = make(map[string]interface{})
	}
	contentType := ""
	startTime := time.Now()
	resp, err := mcputils.ForwardRequest(ctx, upstream, "GET", "/rest/agile/1.0/board/{boardId}/epic/{epicId}/issue", args, []string{"boardId", "epicId"}, contentType)
	if err != nil {
		return nil, fmt.Errorf("upstream request failed: %w", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read upstream response: %w", err)
	}

	mcputils.LogResponse(ctx, resp.StatusCode, "GET", resp.Request.URL.String(), time.Since(startTime), body)

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return mcp.NewToolResultError(fmt.Sprintf("upstream error: status %d, body: %s", resp.StatusCode, string(body))), nil
	}

	if filePath, err := mcputils.SaveBinaryResponse(resp, body, "GetIssuesForEpic"); err != nil {
		return mcp.NewToolResultError(err.Error()), nil
	} else if filePath != "" {
		return mcp.NewToolResultText(fmt.Sprintf("Saved to: %s (%d bytes)", filePath, len(body))), nil
	}

	return mcp.NewToolResultText(string(body)), nil
}
